### Convert Slate Link Node with Children to Lexical Format

Source: https://github.com/payloadcms/payload/blob/main/docs/rich-text/migration.mdx

Shows how to convert complex Slate nodes that contain child nodes, such as links. This converter recursively processes children using convertSlateNodesToLexical and preserves link fields including URL, link type, and target behavior while maintaining the node hierarchy.

```typescript
import type { SerializedLinkNode } from '@payloadcms/richtext-lexical'
import type { SlateNodeConverter } from '@payloadcms/richtext-lexical'
import { convertSlateNodesToLexical } from '@payloadcms/richtext-lexical/migrate'

export const SlateLinkConverter: SlateNodeConverter = {
  converter({ converters, slateNode }) {
    return {
      type: 'link',
      children: convertSlateNodesToLexical({
        canContainParagraphs: false,
        converters,
        parentNodeType: 'link',
        slateNodes: slateNode.children || [],
      }),
      direction: 'ltr',
      fields: {
        doc: slateNode.doc || null,
        linkType: slateNode.linkType || 'custom',
        newTab: slateNode.newTab || false,
        url: slateNode.url || '',
      },
      format: '',
      indent: 0,
      version: 2,
    } as const as SerializedLinkNode
  },
  nodeTypes: ['link'],
}
```

